from typing import List

class Solution:
    def maxSumOf3Subarray(self, n: int, nums: List[int]) -> int:
        if n < 3:
            return 0
        maxVal = float('-inf')
        for i in range(n - 2):
            for j in range(i + 1, n - 1):
                for k in range(j + 1, n):
                    sum = nums[i] + nums[j] + nums[k]
                    maxVal = max(sum, maxVal)
        return maxVal

if __name__ == '__main__':
    n = int(input().split()[0])
    nums = list(map(int, input().split()))
    solution = Solution()
    print(solution.maxSumOf3Subarray(n, nums))

