from typing import List

class Solution {
 public:
 int maxSumOf3Subarray(int n, int* nums, int* output) {
 if (n < 3)
 return 0;
 int maxVal = INT_MIN;
 for (int i = 0; i < n-2; i++)
 for (int j = i+1; j < n-1; j++)
 for (int k = j+1; k < n; k++)
 {
 int sum = nums[i] + nums[j] + nums[k];
 maxVal = max(sum, maxVal);
 }
 output[0] = maxVal;
 return 0;
 }
};

int main() {
 int n; cin >> n;
 int nums[n];
 for(int i = 0; i < n; i++)
 cin >> nums[i];
 int output[1];
 Solution().maxSumOf3Subarray(n, nums, output);
 cout << output[0];
 return 0;
}
